+/** Call a single-input WASM function that returns binary data. */
+function callWasmBinary(
+  fn: (inPtr: number, inLen: number, outPtr: number, outCap: number) => number,
+  inputJson: string,
+  outCap: number,
+): Uint8Array | null {
