+    w += writeInt(out[w..], x2);
+    w += copySlice(out[w..], ",");
+    w += writeInt(out[w..], y2);
+    w += copySlice(out[w..], "],[");
+    w += writeInt(out[w..], x3);
+    w += copySlice(out[w..], ",");
+    w += writeInt(out[w..], y3);
+    w += copySlice(out[w..], "],[");
+    w += writeInt(out[w..], x4);
+    w += copySlice(out[w..], ",");
+    w += writeInt(out[w..], y4);
+    w += copySlice(out[w..], "]]");
+    return w;
