+const MAX_ELEMS = 512;
+const MAX_POINTS = 64;
+const PADDING: i32 = 40;
+
+/// Maximum canvas dimensions to keep memory usage reasonable in WASM
+const MAX_CANVAS_W: u32 = 2400;
+const MAX_CANVAS_H: u32 = 1600;
